def get_pfam_info(familia_id):
    base_id = familia_id.split('.')[0]
    if base_id in PFAM_DESCRIPCIONES:
        return PFAM_DESCRIPCIONES[base_id]
    for key in PFAM_DESCRIPCIONES:
        if base_id.startswith(key):
            return PFAM_DESCRIPCIONES[key]
    return None
